import React, { useState, useRef, useCallback, useEffect } from 'react';
import PreRecord from './PreRecord';
import WhileRecord from './WhileRecord';
import PlayBack from './PlayBack';
import Share from './Share';
import SaveConfirm from './SaveConfirm';

function RecordPage() {
  const [screen, setScreen] = useState('pre');
  const [recordedTime, setRecordedTime] = useState(0);
  const [audioBlob, setAudioBlob] = useState(null);
  const [recordingId, setRecordingId] = useState(null);
  const [transcript, setTranscript] = useState('');
  const [error, setError] = useState('');
  const [analyserNode, setAnalyserNode] = useState(null);

  const mediaRecorderRef = useRef(null);
  const audioContextRef = useRef(null);
  const chunksRef = useRef([]);
  const streamRef = useRef(null);
  const recognitionRef = useRef(null);
  const transcriptRef = useRef('');

  const startTranscription = () => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      console.warn('Speech recognition not supported in this browser');
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onresult = (event) => {
      let finalText = transcriptRef.current;
      let interimText = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const result = event.results[i];
        if (result.isFinal) {
          finalText += result[0].transcript + ' ';
          transcriptRef.current = finalText;
        } else {
          interimText += result[0].transcript;
        }
      }

      setTranscript(finalText + interimText);
    };

    recognition.onerror = (event) => {
      console.warn('Speech recognition error:', event.error);
      // Restart on non-fatal errors
      if (event.error === 'no-speech' || event.error === 'audio-capture') {
        try { recognition.start(); } catch (e) { /* already running */ }
      }
    };

    recognition.onend = () => {
      // Auto-restart if still recording
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        try { recognition.start(); } catch (e) { /* already running */ }
      }
    };

    recognitionRef.current = recognition;
    recognition.start();
  };

  const stopTranscription = () => {
    if (recognitionRef.current) {
      recognitionRef.current.onend = null; // prevent auto-restart
      recognitionRef.current.stop();
      recognitionRef.current = null;
    }
  };

  const startRecording = async () => {
    try {
      setError('');
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Audio analyser for waveform
      const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const source = audioCtx.createMediaStreamSource(stream);
      const analyser = audioCtx.createAnalyser();
      analyser.fftSize = 2048;
      source.connect(analyser);
      audioContextRef.current = audioCtx;
      setAnalyserNode(analyser);

      // MediaRecorder
      const recorder = new MediaRecorder(stream);
      chunksRef.current = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        setAudioBlob(blob);
      };

      mediaRecorderRef.current = recorder;
      recorder.start(100);

      // Start live transcription
      startTranscription();

      setScreen('while');
    } catch (err) {
      setError('We need permission to use your microphone. Please allow access and try again.');
      console.error('Recording error:', err);
    }
  };

  const stopRecording = useCallback(() => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
      mediaRecorderRef.current.stop();
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((track) => track.stop());
      streamRef.current = null;
    }
    if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    setAnalyserNode(null);
    stopTranscription();
  }, []);

  const handleRecord = () => {
    transcriptRef.current = '';
    setTranscript('');
    setRecordingId(null);
    startRecording();
  };

  const handlePause = (elapsed) => {
    stopRecording();
    setRecordedTime(elapsed);
    setScreen('playback');
  };

  const handleSave = async (elapsed) => {
    stopRecording();
    if (elapsed !== undefined) setRecordedTime(elapsed);

    // Wait briefly for audioBlob to be set by recorder.onstop
    await new Promise((resolve) => setTimeout(resolve, 300));

    setScreen('share');
  };

  // Upload to DB whenever we move to share screen
  const uploadRecording = async (blob, dur, text) => {
    if (!blob) return;
    try {
      const formData = new FormData();
      formData.append('audio', blob, 'recording.webm');
      formData.append('transcript', text);
      formData.append('duration', dur);
      const res = await fetch('http://localhost:5001/api/recordings', {
        method: 'POST',
        body: formData,
      });
      const data = await res.json();
      if (data.recording) {
        setRecordingId(data.recording.id);
      }
    } catch (err) {
      console.error('Upload failed:', err);
    }
  };

  const handleContinue = () => startRecording();

  const handleRestart = () => {
    setRecordedTime(0);
    setAudioBlob(null);
    setRecordingId(null);
    setTranscript('');
    transcriptRef.current = '';
    setScreen('pre');
  };

  // Upload to DB when recording is saved (entering share screen)
  useEffect(() => {
    if (screen === 'share' && audioBlob) {
      uploadRecording(audioBlob, recordedTime, transcript);
    }
  }, [screen, audioBlob]);

  const handleShare = async () => {
    if (recordingId) {
      try {
        await fetch(`http://localhost:5001/api/recordings/${recordingId}/share`, {
          method: 'POST',
        });
      } catch (err) {
        console.error('Share failed:', err);
      }
    }
    setScreen('save');
  };

  const handleNew = () => {
    setRecordedTime(0);
    setAudioBlob(null);
    setRecordingId(null);
    setTranscript('');
    transcriptRef.current = '';
    setScreen('pre');
  };

  switch (screen) {
    case 'pre':
      return <PreRecord onRecord={handleRecord} error={error} />;
    case 'while':
      return (
        <WhileRecord
          analyserNode={analyserNode}
          transcript={transcript}
          onPause={handlePause}
          onSave={handleSave}
          startTime={recordedTime}
        />
      );
    case 'playback':
      return (
        <PlayBack
          audioBlob={audioBlob}
          transcript={transcript}
          currentTime={recordedTime}
          onContinue={handleContinue}
          onRestart={handleRestart}
          onSave={() => handleSave(recordedTime)}
        />
      );
    case 'share':
      return (
        <Share
          audioBlob={audioBlob}
          transcript={transcript}
          duration={recordedTime}
          onShare={handleShare}
          onNew={handleNew}
        />
      );
    case 'save':
      return (
        <SaveConfirm
          audioBlob={audioBlob}
          transcript={transcript}
          duration={recordedTime}
          onNew={handleNew}
        />
      );
    default:
      return <PreRecord onRecord={handleRecord} error={error} />;
  }
}

export default RecordPage;
